import type { ZodType } from "zod";

import { isAddress } from "@nomicfoundation/hardhat-utils/eth";
import { hexStringToBytes } from "@nomicfoundation/hardhat-utils/hex";
import { z } from "zod";

import { conditionalUnionType } from "@nomicfoundation/hardhat-zod-utils";

const ADDRESS_LENGTH_BYTES = 20;

export const rpcAddress: ZodType<Uint8Array> = conditionalUnionType(
  [
    [
      (data) => Buffer.isBuffer(data) && data.length === ADDRESS_LENGTH_BYTES,
      z.instanceof(Uint8Array),
    ],
    [isAddress, z.string()],
  ],
  "Expected a Buffer with correct length or a valid RPC address string",
).transform((v) => (typeof v === "string" ? hexStringToBytes(v) : v));

export const nullableRpcAddress: ZodType<Uint8Array | null> = rpcAddress
  .or(z.null())
  .describe(
    "Expected a Buffer with correct length, a valid RPC address string, or the null value",
  );

import type { HardhatUserConfigValidationError } from "@nomicfoundation/hardhat-zod-utils";
import type { HardhatUserConfig } from "hardhat/config";

import { validateUserConfigZodType } from "@nomicfoundation/hardhat-zod-utils";
import { z } from "zod";

const typechainUserConfigSchema = z
  .object({
    outDir: z
      .string({
        message:
          "It should be an absolute path specifying where to store the generated types",
      })
      .optional(),
    alwaysGenerateOverloads: z.boolean().optional(),
    dontOverrideCompile: z.boolean().optional(),
    discriminateTypes: z.boolean().optional(),
    tsNocheck: z.boolean().optional(),
  })
  .optional();

export async function validateTypechainUserConfig(
  userConfig: HardhatUserConfig,
): Promise<HardhatUserConfigValidationError[]> {
  return validateUserConfigZodType(
    userConfig.typechain,
    typechainUserConfigSchema,
  );
}

import type { ConfigHooks } from "../../../../types/hooks.js";

import {
  resolveSolidityUserConfig,
  validateSolidityConfig,
  validateSolidityUserConfig,
} from "../config.js";

export default async (): Promise<Partial<ConfigHooks>> => {
  const handlers: Partial<ConfigHooks> = {
    validateUserConfig: async (userConfig) =>
      validateSolidityUserConfig(userConfig),
    resolveUserConfig: async (
      userConfig,
      resolveConfigurationVariable,
      next,
    ) => {
      const resolvedConfig = await next(
        userConfig,
        resolveConfigurationVariable,
      );

      return await resolveSolidityUserConfig(userConfig, resolvedConfig);
    },
    validateResolvedConfig: async (resolvedConfig) =>
      validateSolidityConfig(resolvedConfig),
  };

  return handlers;
};

export function supportProperHex(Assertion: Chai.AssertionStatic): void {
  Assertion.addMethod("properHex", function (this: any, length: number) {
    const subject = this._obj;
    const isNegated = this.__flags.negate === true;

    const isHex = (a: string) => /^0x[0-9a-fA-F]*$/.test(a);
    if (!isHex(subject)) {
      this.assert(
        isNegated, // trick to make this assertion always fail
        `Expected "${subject}" to be a proper hex string, but it contains invalid (non-hex) characters`,
        `Expected "${subject}" NOT to be a proper hex string, but it contains only valid hex characters`,
      );
    }

    this.assert(
      subject.length === length + 2,
      `Expected "${subject}" to be a hex string of length ${
        length + 2
      } (the provided ${length} plus 2 more for the "0x" prefix), but its length is ${
        subject.length
      }`,
      `Expected "${subject}" NOT to be a hex string of length ${
        length + 2
      } (the provided ${length} plus 2 more for the "0x" prefix), but its length is ${
        subject.length
      }`,
    );
  });
}

