import type { TransactionRequest, ethers, TransactionLike } from "ethers";

import { assertArgument, resolveAddress } from "ethers";

import {
  copyRequest,
  resolveProperties,
} from "../ethers-utils/ethers-utils.js";

export async function populate(
  signer: ethers.Signer,
  tx: TransactionRequest,
): Promise<TransactionLike<string>> {
  const pop: any = copyRequest(tx);

  if (pop.to !== null && pop.to !== undefined) {
    pop.to = resolveAddress(pop.to, signer);
  }

  if (pop.from !== null && pop.from !== undefined) {
    const from = pop.from;
    pop.from = Promise.all([
      signer.getAddress(),
      resolveAddress(from, signer),
    ]).then(([address, resolvedFrom]) => {
      assertArgument(
        address.toLowerCase() === resolvedFrom.toLowerCase(),
        "transaction from mismatch",
        "tx.from",
        resolvedFrom,
      );
      return address;
    });
  } else {
    pop.from = signer.getAddress();
  }

  return await resolveProperties(pop);
}

import type { DeploymentParameters } from "@nomicfoundation/ignition-core";

import { HardhatError } from "@nomicfoundation/hardhat-errors";
import { readUtf8File } from "@nomicfoundation/hardhat-utils/fs";
import json5 from "json5";

import { bigintReviver } from "../internal/utils/bigintReviver.js";

export async function readDeploymentParameters(
  filepath: string,
): Promise<DeploymentParameters> {
  try {
    const rawFile = await readUtf8File(filepath);

    return await json5.parse(rawFile.toString(), bigintReviver);
  } catch (e) {
    if (HardhatError.isHardhatError(e)) {
      throw e;
    }

    if (e instanceof Error) {
      throw new HardhatError(
        HardhatError.ERRORS.IGNITION.INTERNAL.FAILED_TO_PARSE_DEPLOYMENT_PARAMETERS,
        {
          filepath,
        },
        e,
      );
    }

    throw e;
  }
}

