import type { Paths } from "./types.js";

import path from "node:path";

import { readJsonFile, writeJsonFile } from "@nomicfoundation/hardhat-utils/fs";
import { getConfigDir } from "@nomicfoundation/hardhat-utils/global-dir";

const LEDGER_FOLDER_NAME = "ledger";
const CACHE_FILE_NAME = "accounts.json";

export async function read(paths?: string): Promise<Paths | undefined> {
  const ledgerCacheFile = paths ?? (await getLedgerCacheFile());
  try {
    return await readJsonFile(ledgerCacheFile);
  } catch (_error) {}
}

export async function write(json: Paths, paths?: string): Promise<void> {
  const ledgerCacheFile = paths ?? (await getLedgerCacheFile());
  await writeJsonFile(ledgerCacheFile, json);
}

async function getLedgerCacheFile(): Promise<string> {
  const configDirPath = await getConfigDir();
  return path.join(configDirPath, LEDGER_FOLDER_NAME, CACHE_FILE_NAME);
}

import type { BlockTag, NumberLike } from "../../../types.js";
import type { EthereumProvider } from "hardhat/types/providers";

import { assertHardhatInvariant } from "@nomicfoundation/hardhat-errors";

import { assertValidAddress } from "../../assertions.js";
import { toRpcQuantity } from "../../conversion.js";
import { toPaddedRpcQuantity } from "../../padding.js";

export async function getStorageAt(
  provider: EthereumProvider,
  address: string,
  index: NumberLike,
  block: NumberLike | BlockTag = "latest",
): Promise<string> {
  await assertValidAddress(address);

  const indexParam = toPaddedRpcQuantity(index, 32);
  const blockParam =
    block === "latest" || block === "earliest" || block === "pending"
      ? block
      : toRpcQuantity(block);

  const data = await provider.request({
    method: "eth_getStorageAt",
    params: [address, indexParam, blockParam],
  });

  assertHardhatInvariant(
    typeof data === "string",
    "Storage data should be a string",
  );

  return data;
}

import type { NumberLike } from "../../../types.js";
import type { Time } from "../time/time.js";
import type { ChainType } from "hardhat/types/network";
import type { EthereumProvider } from "hardhat/types/providers";

import { assertLargerThan } from "../../assertions.js";
import { toBigInt, toRpcQuantity } from "../../conversion.js";

export async function mineUpTo<ChainTypeT extends ChainType | string>(
  provider: EthereumProvider,
  blockNumber: NumberLike,
  time: Time<ChainTypeT>,
): Promise<void> {
  const normalizedBlockNumber = await toBigInt(blockNumber);
  const latestHeight = await toBigInt(await time.latestBlock());

  assertLargerThan(normalizedBlockNumber, latestHeight);

  const blockParam = normalizedBlockNumber - latestHeight;

  await provider.request({
    method: "hardhat_mine",
    params: [toRpcQuantity(blockParam)],
  });
}

import type {
  Duration,
  NetworkHelpers,
  NumberLike,
} from "../../../../types.js";
import type { ChainType } from "hardhat/types/network";
import type { EthereumProvider } from "hardhat/types/providers";

import { toBigInt, toRpcQuantity } from "../../../conversion.js";

export async function increaseTo<ChainTypeT extends ChainType | string>(
  provider: EthereumProvider,
  networkHelpers: NetworkHelpers<ChainTypeT>,
  timestamp: NumberLike | Date,
  duration: Duration,
): Promise<void> {
  const normalizedTimestamp = await toBigInt(
    timestamp instanceof Date
      ? duration.millis(timestamp.valueOf())
      : timestamp,
  );

  await provider.request({
    method: "evm_setNextBlockTimestamp",
    params: [toRpcQuantity(normalizedTimestamp)],
  });

  await networkHelpers.mine();
}

import type { NetworkHelpers, NumberLike } from "../../../../types.js";
import type { ChainType } from "hardhat/types/network";
import type { EthereumProvider } from "hardhat/types/providers";

import { toBigInt, toRpcQuantity } from "../../../conversion.js";

export async function increase<ChainTypeT extends ChainType | string>(
  provider: EthereumProvider,
  networkHelpers: NetworkHelpers<ChainTypeT>,
  amountInSeconds: NumberLike,
): Promise<number> {
  const normalizedAmount = await toBigInt(amountInSeconds);
  const latestTimestamp = await toBigInt(await networkHelpers.time.latest());
  const targetTimestamp = latestTimestamp + normalizedAmount;

  await provider.request({
    method: "evm_setNextBlockTimestamp",
    params: [toRpcQuantity(targetTimestamp)],
  });

  await networkHelpers.mine();

  return await networkHelpers.time.latest();
}

import type { EthereumProvider } from "hardhat/types/providers";

import { HardhatError } from "@nomicfoundation/hardhat-errors";

const chainIdCache = new WeakMap<EthereumProvider, number>();

export async function getChainId(provider: EthereumProvider): Promise<number> {
  const cachedChainId = chainIdCache.get(provider);
  if (cachedChainId !== undefined) {
    return cachedChainId;
  }

  const chainId = Number(await provider.request({ method: "eth_chainId" }));
  chainIdCache.set(provider, chainId);

  return chainId;
}

const DEV_NETWORK_CHAIN_IDS: readonly number[] = [31337, 1337];
export function rejectLocalNetworks(
  networkName: string,
  chainId: number,
): void {
  if (DEV_NETWORK_CHAIN_IDS.includes(chainId)) {
    throw new HardhatError(
      HardhatError.ERRORS.HARDHAT_VERIFY.GENERAL.NETWORK_NOT_SUPPORTED,
      { networkName, chainId },
    );
  }
}

