contract Lock {
  uint public unlockTime;
  address payable public owner;

  event Withdrawal(uint amount, uint when);

  constructor(uint _unlockTime) payable {
    require(
      block.timestamp < _unlockTime,
      "Unlock time should be in the future"
    );

    unlockTime = _unlockTime;
    owner = payable(msg.sender);
  }

  function withdraw() public {
    // Uncomment this line, and the import of "hardhat/console.sol", to print a log in your terminal
    // console.log("Unlock time is %o and block timestamp is %o", unlockTime, block.timestamp);

    require(block.timestamp >= unlockTime, "You can't withdraw yet");
    require(msg.sender == owner, "You aren't the owner");

    emit Withdrawal(address(this).balance, block.timestamp);

    owner.transfer(address(this).balance);
  }
}

import type { SolidityParameterType } from "../../../types/module.js";
import type { EvmTuple, EvmValue } from "../types/evm-execution.js";

import { isArray } from "lodash-es";

import { assertIgnitionInvariant } from "../../utils/assertions.js";

export function convertEvmValueToSolidityParam(
  evmValue: EvmValue,
): SolidityParameterType {
  if (isArray(evmValue)) {
    return evmValue.map(convertEvmValueToSolidityParam);
  }

  if (typeof evmValue === "object") {
    return evmValue.positional.map(convertEvmValueToSolidityParam);
  }

  return evmValue;
}

export function convertEvmTupleToSolidityParam(
  evmTuple: EvmTuple,
): SolidityParameterType[] {
  const converted = convertEvmValueToSolidityParam(evmTuple);

  assertIgnitionInvariant(
    Array.isArray(converted),
    "Failed to convert an EvmTuple to SolidityParameterType[]",
  );

  return converted;
}

import type { EncodeFunctionCallFuture } from "../../../types/module.js";
import type { EncodeFunctionCallExecutionState } from "../../execution/types/execution-state.js";
import type {
  ReconciliationContext,
  ReconciliationFutureResult,
} from "../types.js";

import { reconcileArguments } from "../helpers/reconcile-arguments.js";
import { reconcileFunctionName } from "../helpers/reconcile-function-name.js";
import { reconcileStrategy } from "../helpers/reconcile-strategy.js";

export function reconcileNamedEncodeFunctionCall(
  future: EncodeFunctionCallFuture<string, string>,
  executionState: EncodeFunctionCallExecutionState,
  context: ReconciliationContext,
): ReconciliationFutureResult {
  let result = reconcileFunctionName(future, executionState, context);
  if (result !== undefined) {
    return result;
  }

  result = reconcileArguments(future, executionState, context);
  if (result !== undefined) {
    return result;
  }

  result = reconcileStrategy(future, executionState, context);
  if (result !== undefined) {
    return result;
  }

  return { success: true };
}

import type {
